SELECT total_occurrences, average_frequency
FROM label_statistics
WHERE label_id = 1;

SELECT MAX(assignment_date) AS latest_assignment_date
FROM label_history
WHERE article_id = 0;

SELECT COUNT(DISTINCT user_id) AS unique_users
FROM article_access
WHERE article_id = 1;

SELECT segment_id, article_id
FROM article_labels
WHERE label_id = 0;
